interface ParseOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

interface ErrorRecord {
  row: number;
  message: string;
}

type TypedValue = string | number | boolean | null;

interface Row {
  [key: string]: TypedValue;
}

class CSVResult {
  rows: Row[];
  headers: string[];
  errors: ErrorRecord[];

  constructor(rows: Row[], headers: string[], errors: ErrorRecord[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: Row) => boolean): Row[] {
    return this.rows.filter(predicate);
  }

  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const val = row[column];
      if (typeof val === 'number') {
        return acc + val;
      }
      return acc;
    }, 0);
  }

  average(column: string): number {
    const numericRows = this.rows.filter(row => typeof row[column] === 'number');
    if (numericRows.length === 0) return 0;
    return this.sum(column) / numericRows.length;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<TypedValue, Row[]> {
    const map = new Map<TypedValue, Row[]>();
    for (const row of this.rows) {
      const key = row[column];
      const keyStr = String(key);
      if (!map.has(keyStr)) {
        map.set(keyStr, []);
      }
      map.get(keyStr)!.push(row);
    }
    return map;
  }
}

function coerceType(value: string): TypedValue {
  // Check for null
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for boolean (case insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for integer
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }

  // Check for float
  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  // Default to string
  return value;
}

function parseFields(
  line: string,
  delimiter: string,
  quoteChar: string
): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === quoteChar) {
      if (inQuotes && nextChar === quoteChar) {
        // Escaped quote (two quotes in a row = one literal quote)
        current += quoteChar;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // End of field
      fields.push(current);
      current = '';
      i++;
    } else {
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  if (inQuotes) {
    throw new Error('Unclosed quote in field');
  }

  return fields;
}

function parseCSV(input: string, options?: ParseOptions): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quoteChar = options?.quoteChar ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ErrorRecord[] = [];
  const rows: Row[] = [];
  let headers: string[] = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return new CSVResult([], [], []);
  }

  // Split input into lines
  const lines = input.split(lineSeparator);

  let headersParsed = false;

  for (let lineIdx = 0; lineIdx < lines.length; lineIdx++) {
    const line = lines[lineIdx];

    // Skip empty lines
    if (line.trim() === '') {
      continue;
    }

    try {
      const fields = parseFields(line, delimiter, quoteChar);

      if (!headersParsed) {
        headers = fields;
        headersParsed = true;
      } else {
        const row: Row = {};

        // Ensure we have a field for each header
        for (let i = 0; i < headers.length; i++) {
          const value = fields[i] !== undefined ? fields[i] : '';
          row[headers[i]] = coerceType(value);
        }

        // If there are extra fields, this is a malformed row
        if (fields.length > headers.length) {
          errors.push({
            row: lineIdx,
            message: `Row has ${fields.length} fields but expected ${headers.length}`
          });
          continue;
        }

        rows.push(row);
      }
    } catch (e) {
      errors.push({
        row: lineIdx,
        message: e instanceof Error ? e.message : 'Unknown error during parsing'
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

export { parseCSV, CSVResult, ParseOptions, ErrorRecord, Row, TypedValue };

import { parseCSV, CSVResult } from './csv-parser';

// Simple assertion helper
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEqual(actual: any, expected: any, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(
        expected
      )}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertArrayEquals(
  actual: any[],
  expected: any[],
  message: string
): void {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message} - Array length mismatch. Expected ${expected.length}, got ${actual.length}`
    );
  }
  for (let i = 0; i < actual.length; i++) {
    assertDeepEqual(actual[i], expected[i], `${message}[${i}]`);
  }
}

// Test: Basic parsing
function testBasicParsing(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

  const result = parseCSV(csv);

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertArrayEquals(result.headers, ['name', 'age', 'city'], 'Headers mismatch');
  assertEquals(result.count(), 2, 'Should have 2 rows');

  assertDeepEqual(
    result.rows[0],
    { name: 'John', age: 30, city: 'New York' },
    'First row mismatch'
  );
  assertDeepEqual(
    result.rows[1],
    { name: 'Jane', age: 25, city: 'Los Angeles' },
    'Second row mismatch'
  );
  assertEquals(result.errors.length, 0, 'Should have no errors');

  console.log('вң“ testBasicParsing passed');
}

// Test: Quoted fields with commas
function testQuotedFieldsWithCommas(): void {
  const csv = `name,address,city
John,"123 Main St, Apt 4",New York
Jane,"456 Oak Rd, Suite 200",Los Angeles`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', address: '123 Main St, Apt 4', city: 'New York' },
    'First row mismatch'
  );
  assertDeepEqual(
    result.rows[1],
    { name: 'Jane', address: '456 Oak Rd, Suite 200', city: 'Los Angeles' },
    'Second row mismatch'
  );

  console.log('вң“ testQuotedFieldsWithCommas passed');
}

// Test: Escaped quotes
function testEscapedQuotes(): void {
  const csv = `name,quote
John,"He said ""Hello"""
Jane,"She said ""Goodbye"""`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', quote: 'He said "Hello"' },
    'First row with escaped quotes mismatch'
  );
  assertDeepEqual(
    result.rows[1],
    { name: 'Jane', quote: 'She said "Goodbye"' },
    'Second row with escaped quotes mismatch'
  );

  console.log('вң“ testEscapedQuotes passed');
}

// Test: Custom delimiters
function testCustomDelimiters(): void {
  const csv = `name;age;city
John;30;New York
Jane;25;Los Angeles`;

  const result = parseCSV(csv, { delimiter: ';' });

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertArrayEquals(result.headers, ['name', 'age', 'city'], 'Headers mismatch');
  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', age: 30, city: 'New York' },
    'First row mismatch'
  );

  console.log('вң“ testCustomDelimiters passed');
}

// Test: Custom quote character
function testCustomQuoteChar(): void {
  const csv = `name,address
John,'123 Main St, Apt 4'
Jane,'456 Oak Rd, Suite 200'`;

  const result = parseCSV(csv, { quoteChar: "'" });

  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', address: '123 Main St, Apt 4' },
    'First row mismatch'
  );

  console.log('вң“ testCustomQuoteChar passed');
}

// Test: Type coercion - integers
function testTypeCoercionIntegers(): void {
  const csv = `name,age
John,30
Jane,25`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].age, 'number', 'age should be number');
  assertEquals(result.rows[0].age, 30, 'age value should be 30');
  assertEquals(result.rows[1].age, 25, 'age value should be 25');

  console.log('вң“ testTypeCoercionIntegers passed');
}

// Test: Type coercion - floats
function testTypeCoercionFloats(): void {
  const csv = `name,price
Item A,19.99
Item B,5.50`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].price, 'number', 'price should be number');
  assertEquals(result.rows[0].price, 19.99, 'price value should be 19.99');
  assertEquals(result.rows[1].price, 5.5, 'price value should be 5.5');

  console.log('вң“ testTypeCoercionFloats passed');
}

// Test: Type coercion - booleans
function testTypeCoercionBooleans(): void {
  const csv = `name,active,enabled
John,true,false
Jane,TRUE,FALSE
Bob,True,False`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'active should be true');
  assertEquals(result.rows[0].enabled, false, 'enabled should be false');
  assertEquals(result.rows[1].active, true, 'active should be true (uppercase)');
  assertEquals(result.rows[1].enabled, false, 'enabled should be false (uppercase)');
  assertEquals(result.rows[2].active, true, 'active should be true (title case)');
  assertEquals(result.rows[2].enabled, false, 'enabled should be false (title case)');

  console.log('вң“ testTypeCoercionBooleans passed');
}

// Test: Type coercion - nulls
function testTypeCoercionNulls(): void {
  const csv = `name,middle,nickname,suffix
John,,NULL,Jr.
Jane,Marie,null,Sr.`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].middle, null, 'middle should be null (empty string)');
  assertEquals(result.rows[0].nickname, null, 'nickname should be null (NULL)');
  assertEquals(result.rows[0].suffix, 'Jr.', 'suffix should be string Jr.');
  assertEquals(result.rows[1].nickname, null, 'nickname should be null (null)');

  console.log('вң“ testTypeCoercionNulls passed');
}

// Test: Type coercion - strings stay as strings
function testTypeCoercionStrings(): void {
  const csv = `name,code,note
John,ABC123,This is a string
Jane,XYZ789,123notanumber`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].code, 'string', 'code should be string');
  assertEquals(result.rows[0].code, 'ABC123', 'code value should be ABC123');
  assertEquals(typeof result.rows[1].note, 'string', 'note should be string');
  assertEquals(result.rows[1].note, '123notanumber', 'note value should be 123notanumber');

  console.log('вң“ testTypeCoercionStrings passed');
}

// Test: Malformed rows - error collection
function testMalformedRowsErrorCollection(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles,ExtraField
Bob,35,Chicago`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should only count valid rows');
  assertEquals(result.errors.length, 1, 'Should have 1 error');
  assertEquals(
    result.errors[0].message.includes('4 fields'),
    true,
    'Error should mention field count'
  );

  console.log('вң“ testMalformedRowsErrorCollection passed');
}

// Test: Unclosed quote error
function testUnclosedQuoteError(): void {
  const csv = `name,address
John,"123 Main St
Jane,456 Oak Rd`;

  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, 'Should have 1 error for unclosed quote');
  assert(
    result.errors[0].message.includes('Unclosed'),
    'Error should mention unclosed quote'
  );

  console.log('вң“ testUnclosedQuoteError passed');
}

// Test: Filter functionality
function testFilter(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,Chicago
Alice,28,Boston`;

  const result = parseCSV(csv);

  const over30 = result.filter((row) => (row.age as number) > 30);
  assertEquals(over30.length, 1, 'Should have 1 person over 30');
  assertEquals(over30[0].name, 'Bob', 'Bob should be over 30');

  const fromNewYork = result.filter((row) => row.city === 'New York');
  assertEquals(fromNewYork.length, 1, 'Should have 1 person from New York');
  assertEquals(fromNewYork[0].name, 'John', 'John should be from New York');

  console.log('вң“ testFilter passed');
}

// Test: Sum aggregation
function testSum(): void {
  const csv = `product,price
Apple,1.50
Banana,0.75
Orange,2.00
Grape,3.25`;

  const result = parseCSV(csv);

  const totalPrice = result.sum('price');
  assertEquals(totalPrice, 7.5, 'Sum of prices should be 7.5');

  console.log('вң“ testSum passed');
}

// Test: Average aggregation
function testAverage(): void {
  const csv = `name,score
Alice,85
Bob,90
Charlie,78
Diana,92`;

  const result = parseCSV(csv);

  const avgScore = result.average('score');
  assertEquals(avgScore, 86.25, 'Average score should be 86.25');

  console.log('вң“ testAverage passed');
}

// Test: Count aggregation
function testCount(): void {
  const csv = `id,name
1,John
2,Jane
3,Bob
4,Alice`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 4, 'Count should be 4');

  console.log('вң“ testCount passed');
}

// Test: GroupBy aggregation
function testGroupBy(): void {
  const csv = `name,department,salary
John,Engineering,75000
Jane,Engineering,80000
Bob,Sales,60000
Alice,Sales,65000
Charlie,Marketing,70000`;

  const result = parseCSV(csv);

  const grouped = result.groupBy('department');

  assert(grouped.has('Engineering'), 'Should have Engineering group');
  assert(grouped.has('Sales'), 'Should have Sales group');
  assert(grouped.has('Marketing'), 'Should have Marketing group');

  assertEquals(grouped.get('Engineering')!.length, 2, 'Engineering should have 2 people');
  assertEquals(grouped.get('Sales')!.length, 2, 'Sales should have 2 people');
  assertEquals(grouped.get('Marketing')!.length, 1, 'Marketing should have 1 person');

  console.log('вң“ testGroupBy passed');
}

// Test: Empty input
function testEmptyInput(): void {
  const result = parseCSV('');

  assertEquals(result.rows.length, 0, 'Should have no rows');
  assertEquals(result.headers.length, 0, 'Should have no headers');
  assertEquals(result.errors.length, 0, 'Should have no errors');

  const result2 = parseCSV('   \n  \n  ');
  assertEquals(result2.rows.length, 0, 'Should have no rows for whitespace');

  console.log('вң“ testEmptyInput passed');
}

// Test: Single column
function testSingleColumn(): void {
  const csv = `name
John
Jane
Bob`;

  const result = parseCSV(csv);

  assertEquals(result.headers.length, 1, 'Should have 1 header');
  assertEquals(result.count(), 3, 'Should have 3 rows');
  assertArrayEquals(
    result.rows.map((r) => r.name),
    ['John', 'Jane', 'Bob'],
    'Names should match'
  );

  console.log('вң“ testSingleColumn passed');
}

// Test: Single row (plus header)
function testSingleRow(): void {
  const csv = `name,age,city
John,30,New York`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 1, 'Should have 1 row');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', age: 30, city: 'New York' },
    'Row should match'
  );

  console.log('вң“ testSingleRow passed');
}

// Test: Very large fields
function testVeryLargeFields(): void {
  const largeValue = 'x'.repeat(10000);
  const csv = `id,text
1,"${largeValue}"
2,short`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertEquals(
    (result.rows[0].text as string).length,
    10000,
    'Large field should be preserved'
  );
  assertEquals(result.rows[0].text, largeValue, 'Large field value should match');

  console.log('вң“ testVeryLargeFields passed');
}

// Test: Negative numbers
function testNegativeNumbers(): void {
  const csv = `name,balance,temperature
John,-1500.50,32.5
Jane,-500,-10.2`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].balance, -1500.5, 'Negative float should work');
  assertEquals(result.rows[1].balance, -500, 'Negative integer should work');
  assertEquals(result.rows[1].temperature, -10.2, 'Negative temperature should work');

  console.log('вң“ testNegativeNumbers passed');
}

// Test: Custom line separator
function testCustomLineSeparator(): void {
  const csv = `name,age,city|John,30,New York|Jane,25,Los Angeles`;

  const result = parseCSV(csv, { lineSeparator: '|' });

  assertEquals(result.count(), 2, 'Should have 2 rows');
  assertDeepEqual(
    result.rows[0],
    { name: 'John', age: 30, city: 'New York' },
    'First row should match'
  );

  console.log('вң“ testCustomLineSeparator passed');
}

// Test: Headers with spaces
function testHeadersWithSpaces(): void {
  const csv = `first name,last name,email address
John,Doe,john@example.com
Jane,Smith,jane@example.com`;

  const result = parseCSV(csv);

  assertArrayEquals(
    result.headers,
    ['first name', 'last name', 'email address'],
    'Headers should preserve spaces'
  );
  assertEquals(
    result.rows[0]['first name'],
    'John',
    'Should access column with spaces'
  );

  console.log('вң“ testHeadersWithSpaces passed');
}

// Test: Empty fields
function testEmptyFields(): void {
  const csv = `name,middle,last
John,,Doe
,Robert,Smith`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0].middle, null, 'Empty field should be null');
  assertEquals(result.rows[1].name, null, 'Missing first field should be null');
  assertEquals(result.rows[1].last, 'Smith', 'Last name should be present');

  console.log('вң“ testEmptyFields passed');
}

// Test: Multiple operations chained
function testChainedOperations(): void {
  const csv = `name,department,salary,years
Alice,Engineering,80000,5
Bob,Engineering,75000,3
Charlie,Sales,60000,2
Diana,Sales,65000,4
Eve,Marketing,70000,1`;

  const result = parseCSV(csv);

  // Filter engineers
  const engineers = result.filter((r) => r.department === 'Engineering');
  assertEquals(engineers.length, 2, 'Should have 2 engineers');

  // Calculate average engineering salary
  const engSalaries = engineers.map((e) => e.salary as number);
  const avgEngSalary = engSalaries.reduce((a, b) => a + b, 0) / engSalaries.length;
  assertEquals(avgEngSalary, 77500, 'Average engineer salary should be 77500');

  // Group by department
  const grouped = result.groupBy('department');
  assertEquals(grouped.get('Engineering')!.length, 2, 'Engineering group size');
  assertEquals(grouped.get('Sales')!.length, 2, 'Sales group size');

  // Total salary
  const totalSalary = result.sum('salary');
  assertEquals(totalSalary, 350000, 'Total salary should be 350000');

  console.log('вң“ testChainedOperations passed');
}

// Run all tests
function runAllTests(): void {
  console.log('Starting CSV Parser Tests...\n');

  try {
    testBasicParsing();
    testQuotedFieldsWithCommas();
    testEscapedQuotes();
    testCustomDelimiters();
    testCustomQuoteChar();
    testTypeCoercionIntegers();
    testTypeCoercionFloats();
    testTypeCoercionBooleans();
    testTypeCoercionNulls();
    testTypeCoercionStrings();
    testMalformedRowsErrorCollection();
    testUnclosedQuoteError();
    testFilter();
    testSum();
    testAverage();
    testCount();
    testGroupBy();
    testEmptyInput();
    testSingleColumn();
    testSingleRow();
    testVeryLargeFields();
    testNegativeNumbers();
    testCustomLineSeparator();
    testHeadersWithSpaces();
    testEmptyFields();
    testChainedOperations();

    console.log('\nвң… All tests passed!');
  } catch (error) {
    console.error('\nвқҢ Test failed:', error);
    process.exit(1);
  }
}

runAllTests();

