function assertEquals(actual, expected, message) {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEqual(actual, expected, message) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(
        expected
      )}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertArrayEquals(actual, expected, message) {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message} - Array length mismatch. Expected ${expected.length}, got ${actual.length}`
    );
  }
  for (let i = 0; i < actual.length; i++) {
    assertDeepEqual(actual[i], expected[i], `${message}[${i}]`);
  }
}

